      "vibecastDisabledText": "Les réponses désactivées restent JSON avec activé: false, raison, ttl_seconds, poll_after_seconds et items: [. Les clients n'affichent jamais d'erreurs brutes de fournisseur/cache/décodage/génération.",
      "vibecastReasonsTitle": "Raisons handicapées",
      "vibecastReasonsText": "feature_disabled, premium_unavailable, no_active_playback, playback_inactive, unknown_track, unsupported_backend, supplier_unavailable, generative_provider_unavailable, rate_limited, cache_failure, non autorisé, invalid_client_type, client_type_mismatch et Privacy_disabled.",
      "vibecastParityTitle": "Parité macOS/iOS",
