      "haTitle": "Home Assistant hub",
      "haText": "Spotify authorization, including your own Spotify Developer app and Client ID, voice assist, device pairing and client configuration run centrally through Home Assistant.",
      "announceTitle": "DJ announcements",
      "announceText": "Receive spoken or visible DJ feedback. Realtime client mood drives the prompt style: 0-24 chill is late-night radio, 25-59 groove classic radio, 60-84 energy energetic and 85-100 party tight. The backend voice profile is fallback when the client sends no valid mood; Home Assistant TTS/Assist still determines the actual audio voice.",
      "secureTitle": "Secure pairing",
      "secureText": "Spotify credentials stay in Home Assistant. ESP32 stores no Spotify credentials and receives no Ask DJ chat history.",
      "interfacesTitle": "Interfaces",
      "interfacesLead": "DJConnect is made for multiple screens and usage contexts, with the same logic underneath.",
      "macosText": "Desktop control for fixed control over search, output, playback, status and the same VibeCast feed as iOS.",
      "windowsText": "Desktop control with Ask DJ, playback actions and secure token storage in Windows Credential Manager.",
      "iosText": "Mobile control nearby: request music, continue Ask DJ, show VibeCast, receive optional notifications and use your Home Assistant pairing.",
      "raspberryText": "As a fixed app on a small screen or dedicated music controller.",
      "espText": "Embedded control with physical interaction, local networking and pairing through Home Assistant.",
      "bonusTitle": "Bonus: mini-games",
      "bonusText": "For playful moments, DJConnect includes four mini-games: Paddle Rally, Meteor Run, Sky Dash & Maze Chase.",
      "usersTitle": "For users",
      "usersText": "Start with the setup flow, connect DJConnect to Home Assistant, download your app or firmware and then use the same music workflow on your favorite client.",
      "usersCta": "Get started",
      "legalPrivacy": "Privacy: DJConnect stores account tokens and pairing details in the app or Home Assistant. This website does not receive or store account details.",
      "legalPrivacyLink": "Privacy Policy",
      "legalSupport": "Support",
      "vibecastTitle": "VibeCast",
      "vibecastLead": "VibeCast is a premium-ready DJConnect feed for Apple clients. Home Assistant remains the source of truth for what is playing; the backend creates safe track, artist, album and vibe items for iOS, macOS and watchOS.",
      "vibecastItem1Title": "Apple parity",
      "vibecastItem1Text": "macOS and iOS use the same endpoint and contract; differences may only be presentation- or capability-driven.",
      "vibecastItem2Title": "Backend-neutral",
      "vibecastItem2Text": "Spotify Direct, Music Assistant and future backends go through the DJConnect backend abstraction, without Spotify-only assumptions.",
      "vibecastItem3Title": "Structured text",
      "vibecastItem3Text": "Clients render safe segments such as text, strong, emphasis, magnify, accent and line_break; no HTML or Markdown parser is required.",
      "vibecastItem4Title": "Graceful capability fallback",
      "vibecastItem4Text": "If a client lacks a capability such as magnify, presentation degrades gracefully without changing item meaning.",
      "vibecastItem5Title": "Polling now, push later",
      "vibecastItem5Text": "Clients follow ttl_seconds and poll_after_seconds; WebSocket or push can be added later without breaking the contract.",
      "vibecastItem6Title": "Safe disabled states",
      "vibecastItem6Text": "Disabled responses stay JSON with enabled:false, reason and items:[]; clients never show raw provider, cache, decode or generation errors.",
      "vibecastCta": "View VibeCast contract",
      "vibecastCoreTitle": "VibeCast feed",
      "vibecastCoreText": "A first-class Apple client feature for short, safe vibe items about the current playback context, with explicit macOS/iOS parity."
