    "en": {
      "title": "DJConnect Privacy Policy",
      "metaDescription": "DJConnect Privacy Policy: what the website, apps and Home Assistant integration do and do not process.",
      "navLabel": "Navigation",
      "languageToggle": "Language",
      "navMenu": "Menu",
      "navHome": "Home",
      "navPrivacy": "Privacy",
      "navStart": "Get started",
      "heroTitle": "Privacy Policy",
      "heroLead": "DJConnect is designed to keep your music control private. Account details stay in your app or Home Assistant; this website does not use cookies or tracking profiles.",
      "summaryTitle": "Short summary",
      "summary1": "No DJConnect cloud account is needed for core use.",
      "summary2": "Spotify credentials stay in Home Assistant. Music Assistant provider credentials stay in Music Assistant/Home Assistant; apps store only their own pairing state.",
      "summaryMusicDna": "Music DNA is opt-in. Ask DJ works without Music DNA.",
      "summary3": "Website download and HACS clicks are counted only as cookieless daily totals.",
      "summary4": "Support email is processed from the information you choose to send to support@djconnect.dev.",
      "websiteTitle": "Website",
      "websiteText": "The DJConnect website is static and does not use advertising cookies, tracking cookies or visitor profiles. Download and HACS links may use privacy-friendly redirect endpoints. Those count only daily totals by target and source, without storing IP address, user agent, referrer or unique visitor ID.",
      "appsTitle": "Apps and Home Assistant",
      "appsText": "Pairing happens locally. Remote pairing is not supported. DJConnect apps store only their own pairing state; Spotify OAuth with Spotify Direct stays internal to Home Assistant and Music Assistant provider credentials stay in Music Assistant/Home Assistant. ESP32 stores no Spotify credentials and receives no Ask DJ chat history.",
      "aiTitle": "Ask DJ and Music DNA",
      "aiText": "DJConnect is designed as a Home Assistant-first system. The Home Assistant integration orchestrates Ask DJ, playback, Assist/STT/TTS and Music DNA. Ask DJ works without Music DNA. Without opt-in, Ask DJ uses no stored personal Music DNA context.",
      "musicDnaTitle": "Music DNA is opt-in",
      "musicDnaText": "Music DNA is opt-in. Until you enable it, DJConnect does not build Music DNA knowledge from Ask DJ, listening profiles, recent tracks, preferences, or recommendations. After opt-in, Home Assistant may build compact signals such as successful playback/Play Now choices, recent playback metadata, artists and genres where available, Track Insight energy/genre analysis, realtime mood samples and compact Spotify profile/recently-played/top data where the backend fetches it.",
      "clearDnaTitle": "Clear Music DNA",
      "clearDnaText": "You can clear Music DNA at any time. If Music DNA remains enabled, DJConnect starts learning again from an empty profile. If you turn it off, learned DNA is cleared and future learning stops.",
      "clientDnaTitle": "Clients and profile data",
      "clientDnaText": "Clients do not store your persistent Music DNA profile. The Music DNA dashboard fetches server-side cards from Home Assistant, such as summary, favorite genres, favorite artists, energy profile, mood/taste direction, recent tracks, based on and updated.",
      "notificationsTitle": "Apple notifications",
      "notificationsText": "iOS, macOS and Apple Watch can use optional push notifications through the DJConnect push relay at api.djconnect.dev. Home Assistant and the relay store only push routing metadata and minimal audit data. Push messages are minimal wake/attention hints and contain no Spotify tokens, Home Assistant tokens, raw prompts, full Music DNA/history, audio or long DJ replies.",
      "voiceTitle": "Voice and audio",
      "voiceText": "When you use DJConnect with Home Assistant Assist, speech recognition, language and TTS are handled by your own Home Assistant Assist pipeline. DJConnect's active integration routes use Home Assistant Assist/STT/TTS and do not call direct external AI/STT/TTS APIs.",
      "logsTitle": "Diagnostics and logs",
      "logsText": "Diagnostics and logs redact secrets and should not contain raw audio, full prompts, full Ask DJ history or Music DNA dumps. Music DNA must not store OAuth tokens, bearer tokens, raw audio, full prompts or unbounded Spotify listening history.",
      "supportTitle": "Support and feedback",
      "supportText": "If you email support, we process the information you choose to send so we can answer your question. Do not send passwords, OAuth tokens, WiFi passwords or other secrets. Use support@djconnect.dev for privacy questions.",
      "rightsTitle": "Questions or requests",
      "rightsText": "For privacy questions, correction requests or deletion requests, email",
      "faqAskDjDnaQuestion": "Does Ask DJ require Music DNA?",
      "faqAskDjDnaAnswer": "No. Ask DJ works without Music DNA. Without opt-in, Ask DJ still works for questions, music control, Track Insight and regular responses.",
      "faqDnaStoredQuestion": "Where is Music DNA stored?",
      "faqDnaStoredAnswer": "Music DNA is server-side in Home Assistant, not a client-local profile. Clients do not store your persistent Music DNA profile.",
      "faqDnaDeleteQuestion": "Can I delete Music DNA?",
      "faqDnaDeleteAnswer": "You can clear Music DNA at any time. Clear removes learned Music DNA and keeps the opt-in setting; if Music DNA is enabled, learning restarts from empty.",
      "faqSpotifyQuestion": "Does DJConnect store Spotify credentials on devices?",
      "faqSpotifyAnswer": "No. Spotify credentials stay in Home Assistant. ESP32 stores no Spotify credentials and receives no Ask DJ chat history.",
      "faqCloudQuestion": "Does DJConnect send raw audio or prompts to its own cloud?",
      "faqCloudAnswer": "No. DJConnect's active integration routes use Home Assistant Assist/STT/TTS and do not call direct external AI/STT/TTS APIs. Raw audio is not stored by default.",
      "faqSpotifyAffiliationQuestion": "Is DJConnect affiliated with Spotify?",
      "faqSpotifyAffiliationAnswer": "DJConnect is not affiliated with, endorsed by, or sponsored by Spotify AB.",
      "legalPrivacy": "Privacy: DJConnect stores account tokens and pairing details in the app or Home Assistant. This website does not receive or store account details.",
      "legalPrivacyLink": "Privacy Policy",
      "legalSupport": "Support"
    },
